#!/usr/bin/perl

use strict;
use warnings;

# Retrieve comment from QUERY_STRING for simplicity.
# For POST requests, you'd read from STDIN.
# A basic parsing for a 'comment' parameter.
my $comment = '';
if (defined $ENV{QUERY_STRING}) {
    foreach my $pair (split /&/, $ENV{QUERY_STRING}) {
        my ($key, $value) = split /=/, $pair, 2;
        if (defined $key && $key eq 'comment') {
            # URL decode the value
            $value =~ tr/+/ /;
            $value =~ s/%([a-fA-F0-9]{2})/pack("C", hex($1))/eg;
            $comment = $value;
            last;
        }
    }
}

print "Content-type: text/html\n\n";
print "<html><head><title>User Comment</title></head><body>";
print "<h1>User Comment:</h1>";
print "<div>$comment</div>";
print "</body></html>";